{action_set_definitions}: {
  "get_environment_state": {
    "description": "Retrieves the current state of the 'api-gateway' deployment, including replica counts, CPU/memory usage, incoming traffic (QPS), HPA settings, and cloud-bursting status.",
    "parameters": {
      "type": "object",
      "properties": {
        "deployment_name": {
          "type": "string",
          "description": "The name of the deployment to inspect."
        }
      },
      "required": [
        "deployment_name"
      ]
    },
    "example_output": {
      "current_replicas": 4,
      "cpu_utilization_pct": 70,
      "incoming_qps": 100,
      "hpa_min": 2,
      "hpa_max": 10,
      "hpa_target_cpu": 70,
      "cloud_bursting_enabled": false
    }
  },
  "configure_autoscaling": {
    "description": "Updates the Horizontal Pod Autoscaler (HPA) settings for the specified deployment.",
    "parameters": {
      "type": "object",
      "properties": {
        "deployment_name": {
          "type": "string",
          "description": "The name of the deployment."
        },
        "min_replicas": {
          "type": "integer",
          "description": "The minimum number of pod replicas."
        },
        "max_replicas": {
          "type": "integer",
          "description": "The maximum number of pod replicas."
        },
        "target_cpu_utilization": {
          "type": "integer",
          "description": "The target CPU utilization percentage for the HPA."
        }
      },
      "required": [
        "deployment_name"
      ]
    },
    "example_output": {
      "status": "applied",
      "new_config": {
        "min_replicas": 2,
        "max_replicas": 20,
        "target_cpu_utilization": 70
      }
    }
  },
  "set_cloud_bursting_policy": {
    "description": "Configures whether the deployment can scale into the cloud once the local capacity of 10 replicas is reached and sets the termination priority.",
    "parameters": {
      "type": "object",
      "properties": {
        "deployment_name": {
          "type": "string",
          "description": "The name of the deployment."
        },
        "allow_cloud_bursting": {
          "type": "boolean",
          "description": "Enable or disable scaling beyond the local cluster limit."
        },
        "termination_order": {
          "type": "string",
          "enum": [
            "cloud-first",
            "local-first",
            "random"
          ],
          "description": "Determines which replicas are terminated first during scale-down."
        }
      },
      "required": [
        "deployment_name",
        "allow_cloud_bursting",
        "termination_order"
      ]
    },
    "example_output": {
      "cloud_bursting_active": true,
      "termination_policy": "cloud-first"
    }
  },
  "advance_traffic_simulation": {
    "description": "Transitions the environment through the specific traffic volatility event: Initial (100 QPS) -> Surge (450 QPS) -> Final Baseline (50 QPS). Each call progresses the simulation to the next logical phase and returns the updated environmental metrics.",
    "parameters": {
      "type": "object",
      "properties": {
        "deployment_name": {
          "type": "string",
          "description": "The deployment to track during the traffic transition."
        }
      },
      "required": [
        "deployment_name"
      ]
    },
    "example_output": {
      "current_phase": "Peak Surge",
      "incoming_qps": 450,
      "cpu_utilization_pct": 72,
      "current_replicas": 18,
      "cloud_replicas": 8
    }
  }
}
